   152	
   153	                        _currentIdx = 1;
   154	                    }
   155	                    else
   156	                    {
   157	                        _currentIdx = Sequence.Length - 1;
   158	                    }
   159	                }
   160	            }
   161	
   162	            _lastRender = DateTime.Now;
   163	        }
   164	
   165	        if (setNeedsDraw)
   166	        {
   167	            SetNeedsDraw ();
   168	        }
